def write(self):
        # type: () -> Text
        imports = []
        for pkg, items in self.imports.items():
            imports.append(u"from {} import (".format(pkg))
            for item in sorted(items):
                imports.append(u"    {},".format(item))
            imports.append(u")\n")

        return "\n".join(imports + self.lines)

