def is_carmichael(n):
        if n >= 0:
            if (n == 1) or isprime(n) or (n % 2 == 0):
                return False

            divisors = list([1, n])

            # get divisors
            for i in range(3, n // 2 + 1, 2):
                if n % i == 0:
                    divisors.append(i)

            for i in divisors:
                if is_square(i) and i != 1:
                    return False
                if isprime(i):
                    if not _divides(i - 1, n - 1):
                        return False

            return True

        else:
            raise ValueError('The provided number must be greater than or equal to 0')

