                ds_tables = [TablesRow(TABLE_TYPE=TABLES_ROW_TYPE.BASE_TABLE, TABLE_NAME=x['name']) for x in ds_tables]
            elif isinstance(ds_tables, list) and isinstance(ds_tables[0], str):
